export const KNOWN_AVATAR_SLUG_MAP: Record<string, string> = {
  "ceo": "hybridCeo",
  "pm": "hybridPm",
  "fe": "hybridFe",
  "frontend": "hybridFe",
  "be": "hybridBe",
  "backend": "hybridBe",
  "eng": "hybridEng",
  "gtm": "hybridGtm",
  "ai": "hybridAi",
  "ai-eng": "hybridAi",
  "ai_eng": "hybridAi",
  "designer": "hybridDesigner",
  "cmo": "hybridCmo",
  "cro": "hybridCro",
  "pam": "hybridPam",
  "pamcute": "hybridPamCute",
  "pam-cute": "hybridPamCute",
  "pam-soft": "hybridPamCute",
  "pam-legacy": "hybridPamCute",
  "human": "hybridHuman",
  "you": "hybridHuman",
  "nex": "hybridNex",
  "generic": "hybridGeneric",
  "qa": "hybridQa",
  "ae": "hybridAe",
  "sdr": "hybridSdr",
  "research": "hybridResearch",
  "content": "hybridContent"
}

export function resolveKnownPortraitSprite(slug: string): KnownAvatarSprite | null {
  const key = KNOWN_AVATAR_SLUG_MAP[slug.toLowerCase()]
  return key ? KNOWN_AVATAR_SPRITES[key] ?? null : null
}
